import React from 'react';
import './Hero.css';

const Hero = () => {
  const scrollToContact = () => {
    const element = document.getElementById('contact');
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <section className="hero">
      <div className="container">
        <div className="hero-content">
          <h1 className="hero-title">
            Specialist Accountants for Your Business
          </h1>
          <p className="hero-subtitle">
            Professional accounting and tax services tailored to your needs. 
            Let Greyline Accountants Ltd. handle your finances so you can focus on growing your business.
          </p>
          <div className="hero-buttons">
            <button className="btn-primary btn-large" onClick={scrollToContact}>
              Schedule a Free Consultation
            </button>
            <button className="btn-secondary btn-large" onClick={() => {
              document.getElementById('services')?.scrollIntoView({ behavior: 'smooth' });
            }}>
              Our Services
            </button>
          </div>
          <div className="hero-features">
            <div className="feature-item">
              <span className="feature-icon">✓</span>
              <span>Expert Accountants</span>
            </div>
            <div className="feature-item">
              <span className="feature-icon">✓</span>
              <span>Tax Planning</span>
            </div>
            <div className="feature-item">
              <span className="feature-icon">✓</span>
              <span>Cloud Accounting</span>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
